{"tool":"resolve_intent_packet","arguments":{"object_id":"...","source_slot":"...","target_slot":"...","constraints":{"speed_cap":"SLOW"},"semantic_subtasks":[{"name":"pre_grasp_align","description":"...","posture_constraint":"keep tray level"}]}}

